    scale = float(scale)
    if scale <= 0:
        raise ValueError("scale must be greater than 0")
    source = _as_rgb(image)
    width, height = source.size
    new_size = (max(1, round(width * scale)), max(1, round(height * scale)))
    return source.resize(new_size)


